import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import AdminLayout from './AdminLayout';
import { MOCK_MATERIALS, MOCK_EQUIPMENT } from '../../constants';
import { Material, Equipment } from '../../types';
import { AlertTriangle, AlertCircle, Plus, Pencil, Trash2, X, Save, Package, Truck, CheckCircle2 } from 'lucide-react';

const Inventory: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();

  // --- State Management ---
  const [activeTab, setActiveTab] = useState<'material' | 'alat'>('material');
  const [materials, setMaterials] = useState<Material[]>(MOCK_MATERIALS);
  const [equipment, setEquipment] = useState<Equipment[]>(MOCK_EQUIPMENT);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentId, setCurrentId] = useState<string | null>(null);
  const [itemToDelete, setItemToDelete] = useState<{ id: string, name: string } | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    unit: '',
    currentStock: 0,
    minThreshold: 0,
    type: '',
    status: 'Tersedia'
  });

  useEffect(() => {
    if (location.pathname.includes('/equipment')) {
      setActiveTab('alat');
    } else {
      setActiveTab('material');
    }
  }, [location.pathname]);

  const handleTabChange = (tab: 'material' | 'alat') => {
    setActiveTab(tab);
    navigate(tab === 'material' ? '/admin/inventory' : '/admin/equipment');
  };

  const openAddModal = () => {
    setIsEditing(false);
    setCurrentId(null);
    setFormData({
      name: '',
      unit: 'Sak',
      currentStock: 0,
      minThreshold: 0,
      type: 'Alat Berat',
      status: 'Tersedia'
    });
    setIsModalOpen(true);
  };

  const openEditModal = (item: any) => {
    setIsEditing(true);
    setCurrentId(item.id);

    if (activeTab === 'material') {
      setFormData({
        name: item.name,
        unit: item.unit,
        currentStock: item.currentStock,
        minThreshold: item.minThreshold,
        type: '',
        status: ''
      });
    } else {
      setFormData({
        name: item.name,
        unit: '',
        currentStock: 0,
        minThreshold: 0,
        type: item.type,
        status: item.status
      });
    }
    setIsModalOpen(true);
  };

  const confirmDelete = (item: any) => {
    setItemToDelete({ id: item.id, name: item.name });
  };

  const executeDelete = () => {
    if (!itemToDelete) return;
    if (activeTab === 'material') {
      setMaterials(prev => prev.filter(m => m.id !== itemToDelete.id));
    } else {
      setEquipment(prev => prev.filter(e => e.id !== itemToDelete.id));
    }
    setItemToDelete(null);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeTab === 'material') {
      const newMaterial: Material = {
        id: isEditing && currentId ? currentId : `m-${Date.now()}`,
        name: formData.name,
        unit: formData.unit,
        currentStock: Number(formData.currentStock),
        minThreshold: Number(formData.minThreshold),
        lastUpdated: new Date().toISOString().split('T')[0]
      };
      if (isEditing) {
        setMaterials(prev => prev.map(m => m.id === currentId ? newMaterial : m));
      } else {
        setMaterials(prev => [...prev, newMaterial]);
      }
    } else {
      const newEquipment: Equipment = {
        id: isEditing && currentId ? currentId : `e-${Date.now()}`,
        name: formData.name,
        type: formData.type,
        status: formData.status as 'Tersedia' | 'Dipakai' | 'Perbaikan'
      };
      if (isEditing) {
        setEquipment(prev => prev.map(e => e.id === currentId ? newEquipment : e));
      } else {
        setEquipment(prev => [...prev, newEquipment]);
      }
    }
    setIsModalOpen(false);
  };

  const getStockStatus = (current: number, min: number) => {
    if (current === 0) {
      return {
        id: 'critical',
        label: 'STOK HABIS',
        className: 'text-white bg-red-600 dark:bg-red-500 shadow-lg shadow-red-500/30 animate-pulse px-3',
        icon: <AlertCircle className="h-4 w-4 mr-2" />
      };
    }
    if (current <= min) {
      return {
        id: 'warning',
        label: 'KRITIS: SEGERA BELI',
        className: 'text-white bg-orange-600 dark:bg-orange-500 shadow-lg shadow-orange-500/20 px-3',
        icon: <AlertTriangle className="h-4 w-4 mr-2" />
      };
    }
    return null;
  };

  return (
    <AdminLayout title="Manajemen Stok & Peralatan">
      <div className="mb-6 border-b border-slate-200 dark:border-slate-700">
        <nav className="-mb-px flex space-x-8">
          <button
            onClick={() => handleTabChange('material')}
            className={`${
              activeTab === 'material'
                ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                : 'border-transparent text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300 hover:border-slate-300'
            } whitespace-nowrap py-4 px-1 border-b-2 font-bold text-sm transition-colors flex items-center`}
          >
            <Package className="w-4 h-4 mr-2" />
            Stok Material
          </button>
          <button
            onClick={() => handleTabChange('alat')}
            className={`${
              activeTab === 'alat'
                ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                : 'border-transparent text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300 hover:border-slate-300'
            } whitespace-nowrap py-4 px-1 border-b-2 font-bold text-sm transition-colors flex items-center`}
          >
            <Truck className="w-4 h-4 mr-2" />
            Armada & Peralatan
          </button>
        </nav>
      </div>

      {activeTab === 'material' ? (
        <div className="bg-white dark:bg-slate-800 shadow-sm rounded-2xl border border-slate-100 dark:border-slate-700 overflow-hidden animate-in fade-in duration-300">
          <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900/50">
             <div className="flex items-center gap-3">
               <h3 className="text-lg leading-6 font-bold text-slate-900 dark:text-white">Gudang Material Utama</h3>
               <span className="text-xs bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 px-2 py-1 rounded-full font-bold">
                 {materials.length} Item
               </span>
             </div>
             <button 
               onClick={openAddModal}
               className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-bold rounded-xl text-white bg-blue-600 hover:bg-blue-700 transition-colors shadow-lg shadow-blue-600/20"
             >
               <Plus className="mr-2 h-4 w-4" /> Tambah Stok
             </button>
          </div>
          <ul className="divide-y divide-slate-100 dark:divide-slate-700">
            {materials.length > 0 ? materials.map((item) => {
              const status = getStockStatus(item.currentStock, item.minThreshold);
              const isCritical = item.currentStock <= item.minThreshold;

              return (
              <li key={item.id} className={`px-6 py-5 transition-all group border-l-4 ${
                isCritical 
                  ? 'border-red-500 bg-red-50/40 dark:bg-red-900/10' 
                  : 'border-transparent hover:bg-slate-50 dark:hover:bg-slate-700/30'
              }`}>
                <div className="flex items-center justify-between">
                  <div className="flex flex-col">
                     <p className={`text-sm font-bold truncate ${isCritical ? 'text-red-700 dark:text-red-400' : 'text-blue-600 dark:text-blue-400'}`}>
                        {item.name}
                        {isCritical && <span className="ml-2 inline-flex items-center text-[10px] font-black uppercase text-red-600 dark:text-red-500">⚠️ PERLU PENGADAAN</span>}
                     </p>
                     <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
                        Satuan: <span className="font-semibold">{item.unit}</span> | Batas Minimum: <span className="font-bold text-slate-700 dark:text-slate-300">{item.minThreshold}</span>
                     </p>
                  </div>
                  <div className="flex items-center gap-6">
                     <div className="text-right">
                        <p className={`text-3xl font-black tabular-nums ${item.currentStock === 0 ? 'text-red-600 animate-pulse' : isCritical ? 'text-orange-600' : 'text-slate-900 dark:text-white'}`}>
                          {item.currentStock}
                        </p>
                        <p className="text-[10px] text-slate-500 dark:text-slate-400 font-black uppercase tracking-widest">Sisa Stok</p>
                     </div>

                     {status && (
                        <div className={`hidden lg:flex items-center py-2 rounded-xl font-bold text-[11px] ${status.className}`}>
                           {status.icon}
                           {status.label}
                        </div>
                     )}

                     <div className="flex items-center gap-1 pl-4 border-l border-slate-200 dark:border-slate-700">
                        <button 
                          onClick={() => openEditModal(item)}
                          className="p-2.5 rounded-xl text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/30 transition-all active:scale-90"
                          title="Edit"
                        >
                          <Pencil className="w-4 h-4" />
                        </button>
                        <button 
                          onClick={() => confirmDelete(item)}
                          className="p-2.5 rounded-xl text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 transition-all active:scale-90"
                          title="Hapus"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                     </div>
                  </div>
                </div>
              </li>
            )}) : (
              <li className="px-6 py-12 text-center text-slate-500 dark:text-slate-400 italic">Data material kosong.</li>
            )}
          </ul>
        </div>
      ) : (
        <div className="bg-white dark:bg-slate-800 shadow-sm rounded-2xl border border-slate-100 dark:border-slate-700 overflow-hidden animate-in fade-in duration-300">
          <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900/50">
             <h3 className="text-lg leading-6 font-bold text-slate-900 dark:text-white">Daftar Alat Berat & Kendaraan</h3>
             <button 
               onClick={openAddModal}
               className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-bold rounded-xl text-white bg-blue-600 hover:bg-blue-700 transition-colors shadow-lg shadow-blue-600/20"
             >
               <Plus className="mr-2 h-4 w-4" /> Tambah Alat
             </button>
          </div>
           <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3 p-6">
             {equipment.length > 0 ? equipment.map((item) => (
               <div key={item.id} className="relative rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 px-6 py-5 shadow-sm flex items-center space-x-3 hover:border-blue-400 dark:hover:border-blue-600 hover:shadow-md transition-all group">
                 <div className="flex-1 min-w-0">
                    <p className="text-sm font-bold text-slate-900 dark:text-white">{item.name}</p>
                    <p className="text-sm text-slate-500 dark:text-slate-400 truncate mt-1">{item.type}</p>
                 </div>

                 <div className="flex flex-col items-end gap-2">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-black uppercase border ${
                      item.status === 'Tersedia' ? 'bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-300 border-transparent' : 
                      item.status === 'Perbaikan' ? 'bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-300 border-transparent' : 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-800 dark:text-yellow-300 border-transparent'
                    }`}>
                      {item.status}
                    </span>

                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => openEditModal(item)} className="p-1.5 text-slate-400 hover:text-blue-600"><Pencil size={14}/></button>
                        <button onClick={() => confirmDelete(item)} className="p-1.5 text-slate-400 hover:text-red-600"><Trash2 size={14}/></button>
                    </div>
                 </div>
               </div>
             )) : (
               <div className="col-span-full text-center py-12 text-slate-500 dark:text-slate-400 italic">Belum ada data peralatan.</div>
             )}
           </div>
        </div>
      )}

      {/* --- UNIVERSAL ADD/EDIT MODAL --- */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 sm:p-6">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" onClick={() => setIsModalOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-800 rounded-2xl shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200">

            <div className="px-6 py-4 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 flex justify-between items-center">
              <h3 className="text-lg font-bold text-slate-900 dark:text-white">
                {isEditing ? 'Edit Data' : 'Tambah Data'} {activeTab === 'material' ? 'Material' : 'Alat'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 dark:hover:text-white transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleSave} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">
                  Nama {activeTab === 'material' ? 'Material' : 'Alat/Kendaraan'}
                </label>
                <input 
                  type="text" 
                  required
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  className="block w-full rounded-xl border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 text-slate-900 dark:text-white px-4 py-2.5 focus:ring-blue-500 focus:border-blue-500"
                  placeholder={activeTab === 'material' ? 'Contoh: Aspal Curah' : 'Contoh: Excavator Mini'}
                />
              </div>

              {activeTab === 'material' ? (
                <>
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">Stok Saat Ini</label>
                    <input 
                      type="number" 
                      required
                      value={formData.currentStock}
                      onChange={(e) => {
                        const val = Number(e.target.value);
                        setFormData({
                          ...formData, 
                          currentStock: val,
                          minThreshold: Math.ceil(val * 0.2)
                        });
                      }}
                      className="block w-full rounded-xl border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 text-slate-900 dark:text-white px-4 py-2.5 focus:ring-blue-500 focus:border-blue-500 font-bold text-lg"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">Satuan</label>
                      <input 
                        type="text" 
                        required
                        value={formData.unit}
                        onChange={(e) => setFormData({...formData, unit: e.target.value})}
                        className="block w-full rounded-xl border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 text-slate-900 dark:text-white px-4 py-2.5 focus:ring-blue-500 focus:border-blue-500"
                        placeholder="Kg, Sak, m3"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">Batas Minimum</label>
                      <input 
                        type="number" 
                        required
                        value={formData.minThreshold}
                        onChange={(e) => setFormData({...formData, minThreshold: Number(e.target.value)})}
                        className="block w-full rounded-xl border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 text-slate-900 dark:text-white px-4 py-2.5 focus:ring-blue-500 focus:border-blue-500"
                      />
                    </div>
                  </div>
                </>
              ) : (
                <>
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">Tipe / Jenis</label>
                    <input 
                      type="text" 
                      required
                      value={formData.type}
                      onChange={(e) => setFormData({...formData, type: e.target.value})}
                      className="block w-full rounded-xl border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 text-slate-900 dark:text-white px-4 py-2.5 focus:ring-blue-500 focus:border-blue-500"
                      placeholder="Transport / Alat Berat / Tools"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">Status Ketersediaan</label>
                    <select 
                      value={formData.status}
                      onChange={(e) => setFormData({...formData, status: e.target.value})}
                      className="block w-full rounded-xl border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-900 text-slate-900 dark:text-white px-4 py-2.5 focus:ring-blue-500 focus:border-blue-500"
                    >
                      <option value="Tersedia">Tersedia</option>
                      <option value="Dipakai">Sedang Dipakai</option>
                      <option value="Perbaikan">Dalam Perbaikan (Rusak)</option>
                    </select>
                  </div>
                </>
              )}
              <div className="pt-4 flex gap-3">
                 <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 rounded-xl border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-300 font-semibold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">Batal</button>
                 <button type="submit" className="flex-1 py-3 rounded-xl bg-blue-600 text-white font-bold hover:bg-blue-700 shadow-lg shadow-blue-600/30 transition-colors flex justify-center items-center"><Save className="w-4 h-4 mr-2" /> Simpan</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {itemToDelete && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 sm:p-6">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" onClick={() => setItemToDelete(null)}></div>
          <div className="relative w-full max-w-sm bg-white dark:bg-slate-800 rounded-2xl shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 border border-slate-100 dark:border-slate-700">
             <div className="p-6 text-center">
                <div className="mx-auto flex items-center justify-center h-16 w-16 rounded-full bg-red-100 dark:bg-red-900/30 mb-6">
                   <AlertTriangle className="h-8 w-8 text-red-600 dark:text-red-400" />
                </div>
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Hapus Item Ini?</h3>
                <p className="text-slate-500 dark:text-slate-400 text-sm">Anda akan menghapus <span className="font-bold text-slate-800 dark:text-slate-200">"{itemToDelete.name}"</span>. Tindakan ini tidak dapat dibatalkan.</p>
             </div>
             <div className="p-4 bg-slate-50 dark:bg-slate-900/50 flex gap-3">
                <button onClick={() => setItemToDelete(null)} className="flex-1 py-3 px-4 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-xl text-slate-700 dark:text-slate-300 font-semibold hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">Batal</button>
                <button onClick={executeDelete} className="flex-1 py-3 px-4 bg-red-600 hover:bg-red-700 text-white font-bold rounded-xl shadow-lg shadow-red-600/30 transition-colors flex items-center justify-center"><Trash2 className="w-4 h-4 mr-2" /> Ya, Hapus</button>
             </div>
          </div>
        </div>
      )}
    </AdminLayout>
  );
};

export default Inventory;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  MapPin, 
  Camera, 
  Send, 
  AlertCircle, 
  User, 
  Phone, 
  Navigation, 
  CheckCircle2, 
  Home, 
  Truck, 
  Construction,
  X,
  Image as ImageIcon,
  Loader2,
  GpsFixed
} from 'lucide-react';
import PublicNavbar from '../../components/PublicNavbar';
import { RoadType } from '../../types';
// @ts-ignore
import EXIF from 'exif-js';

const SuccessModal = ({ 
  ticketNumber, 
  onClose 
}: { 
  ticketNumber: string, 
  onClose: () => void 
}) => (
  <div className="fixed inset-0 z-[60] flex items-center justify-center px-4 animate-in fade-in duration-300">
    <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose}></div>
    <div className="relative bg-white dark:bg-slate-800 rounded-2xl shadow-2xl max-w-md w-full p-6 text-center scale-100 animate-in zoom-in-95 duration-300 border border-slate-200 dark:border-slate-700">
      <div className="mx-auto flex items-center justify-center h-20 w-20 rounded-full bg-green-100 dark:bg-green-900/30 mb-6">
        <CheckCircle2 className="h-10 w-10 text-green-600 dark:text-green-400" />
      </div>
      <h3 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">Laporan Diterima!</h3>
      <p className="text-slate-500 dark:text-slate-400 mb-6">
        Terima kasih telah peduli dengan kotamu. Tim kami akan segera memverifikasi laporan ini.
      </p>

      <div className="bg-slate-50 dark:bg-slate-900 rounded-lg p-4 mb-6 border border-dashed border-slate-300 dark:border-slate-700">
        <p className="text-xs uppercase tracking-wider text-slate-500 font-semibold mb-1">Nomor Tiket Anda</p>
        <p className="text-3xl font-mono font-bold text-blue-600 dark:text-blue-400 tracking-widest selection:bg-blue-200">{ticketNumber}</p>
        <p className="text-xs text-slate-400 mt-1">(Simpan untuk cek status)</p>
      </div>

      <button 
        onClick={onClose}
        className="w-full py-3 px-4 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl transition-colors shadow-lg shadow-blue-600/30"
      >
        Pantau Status Laporan
      </button>
    </div>
  </div>
);

const CategoryCard = ({ 
  type, 
  selected, 
  onClick, 
  icon: Icon, 
  desc 
}: { 
  type: string, 
  selected: boolean, 
  onClick: () => void, 
  icon: any, 
  desc: string 
}) => (
  <div 
    onClick={onClick}
    className={`relative cursor-pointer rounded-xl border-2 p-4 transition-all duration-200 flex flex-col items-center text-center gap-2 hover:border-blue-300 dark:hover:border-blue-700 ${
      selected 
        ? 'border-blue-600 bg-blue-50 dark:bg-blue-900/20 dark:border-blue-500' 
        : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800'
    }`}
  >
    <div className={`p-3 rounded-full ${selected ? 'bg-blue-100 text-blue-600 dark:bg-blue-800 dark:text-blue-200' : 'bg-slate-100 text-slate-500 dark:bg-slate-700 dark:text-slate-400'}`}>
      <Icon size={24} />
    </div>
    <div>
      <h4 className={`font-bold text-sm ${selected ? 'text-blue-900 dark:text-blue-100' : 'text-slate-700 dark:text-slate-300'}`}>{type}</h4>
      <p className="text-xs text-slate-500 dark:text-slate-400 mt-1 leading-tight">{desc}</p>
    </div>
    {selected && (
      <div className="absolute top-2 right-2">
        <CheckCircle2 size={16} className="text-blue-600 dark:text-blue-400" />
      </div>
    )}
  </div>
);

const ReportForm: React.FC = () => {
  const navigate = useNavigate();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [ticketNumber, setTicketNumber] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    category: RoadType.ARTERI,
    locationDesc: '',
    description: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [location, setLocation] = useState<{lat: number, lng: number} | null>(null);
  const [isExifLocation, setIsExifLocation] = useState(false);
  const [locLoading, setLocLoading] = useState(false);

  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploadingPhoto, setIsUploadingPhoto] = useState(false);

  useEffect(() => {
    return () => {
      if (preview) URL.revokeObjectURL(preview);
    };
  }, [preview]);

  const convertDMSToDD = (degrees: any, minutes: any, seconds: any, direction: string) => {
    let dd = Number(degrees) + Number(minutes) / 60 + Number(seconds) / (60 * 60);
    if (direction === "S" || direction === "W") {
      dd = dd * -1;
    }
    return dd;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (!selectedFile) return;

    if (!selectedFile.type.startsWith('image/')) {
      alert('Mohon upload file gambar.');
      return;
    }

    setFile(selectedFile);
    setIsUploadingPhoto(true);
    setUploadProgress(0);
    setIsExifLocation(false);

    const objectUrl = URL.createObjectURL(selectedFile);
    setPreview(objectUrl);

    // Simulate Upload Progress
    const interval = setInterval(() => {
      setUploadProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsUploadingPhoto(false);
          return 100;
        }
        return prev + 10;
      });
    }, 150);

    // Extract EXIF Metadata
    // @ts-ignore
    EXIF.getData(selectedFile, function(this: any) {
      const latData = EXIF.getTag(this, "GPSLatitude");
      const latRef = EXIF.getTag(this, "GPSLatitudeRef");
      const longData = EXIF.getTag(this, "GPSLongitude");
      const longRef = EXIF.getTag(this, "GPSLongitudeRef");

      if (latData && latRef && longData && longRef) {
        const lat = convertDMSToDD(latData[0], latData[1], latData[2], latRef);
        const lng = convertDMSToDD(longData[0], longData[1], longData[2], longRef);
        setLocation({ lat, lng });
        setIsExifLocation(true);
      }
    });
  };

  const handleRemoveFile = () => {
    setFile(null);
    setPreview(null);
    setUploadProgress(0);
    setIsExifLocation(false);
  };

  const handleGetLocation = () => {
    setLocLoading(true);
    if ('geolocation' in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        setLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude
        });
        setIsExifLocation(false);
        setLocLoading(false);
      }, (error) => {
        alert('Gagal mendapatkan lokasi. Pastikan izin lokasi aktif.');
        setLocLoading(false);
      }, { enableHighAccuracy: true });
    } else {
      alert('Browser tidak mendukung geolokasi.');
      setLocLoading(false);
    }
  };

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.name.trim()) newErrors.name = 'Nama wajib diisi';
    if (!formData.phone.trim()) newErrors.phone = 'Nomor HP wajib diisi';
    if (!formData.locationDesc.trim()) newErrors.locationDesc = 'Patokan lokasi wajib diisi';
    if (!formData.description.trim()) newErrors.description = 'Deskripsi kerusakan wajib diisi';
    if (!file) newErrors.file = 'Foto bukti wajib diunggah';
    if (!location) newErrors.location = 'Titik lokasi GPS diperlukan';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) {
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    setIsSubmitting(true);
    setTimeout(() => {
      setIsSubmitting(false);
      const newTicketId = `PJJ-2024-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
      setTicketNumber(newTicketId);
    }, 2000);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }));
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <PublicNavbar />

      {ticketNumber && <SuccessModal ticketNumber={ticketNumber} onClose={() => navigate('/track')} />}

      <div className="max-w-4xl mx-auto py-10 px-4 sm:px-6 lg:px-8">

        <div className="text-center mb-10">
          <h1 className="text-3xl md:text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight mb-4">
            Lapor Kerusakan Infrastruktur
          </h1>
          <p className="text-lg text-slate-600 dark:text-slate-400 max-w-2xl mx-auto font-medium">
            Sampaikan keluhan Anda secara langsung kepada UPT Jalan & Jembatan Dinas PUPR Kota Banjarmasin.
          </p>
        </div>

        <div className="bg-white dark:bg-slate-900 shadow-2xl shadow-blue-900/5 rounded-3xl overflow-hidden border border-slate-100 dark:border-slate-800">
          <div className="h-2 bg-gradient-to-r from-blue-600 via-blue-400 to-blue-600"></div>

          <form onSubmit={handleSubmit} noValidate className="p-6 md:p-10 space-y-8">

            <section>
              <h3 className="text-lg font-black text-slate-800 dark:text-white flex items-center mb-6 uppercase tracking-tight">
                <span className="flex items-center justify-center w-8 h-8 rounded-xl bg-blue-600 text-white text-sm font-black mr-3 shadow-lg shadow-blue-600/30">1</span>
                Informasi Pelapor
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Nama Lengkap</label>
                  <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                      <User className="h-5 w-5 text-slate-400" />
                    </div>
                    <input 
                      type="text" 
                      name="name" 
                      value={formData.name} 
                      onChange={handleChange} 
                      className={`block w-full pl-11 pr-4 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-800 border ${errors.name ? 'border-red-400 ring-2 ring-red-500/10' : 'border-slate-200 dark:border-slate-700 focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10'} text-slate-900 dark:text-white placeholder-slate-400 transition-all font-medium`} 
                      placeholder="Masukkan nama asli Anda" 
                    />
                  </div>
                  {errors.name && <p className="mt-2 text-xs text-red-500 flex items-center font-bold uppercase tracking-tight"><AlertCircle size={12} className="mr-1" />{errors.name}</p>}
                </div>

                <div>
                  <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Nomor WhatsApp</label>
                  <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                      <Phone className="h-5 w-5 text-slate-400" />
                    </div>
                    <input 
                      type="tel" 
                      name="phone" 
                      value={formData.phone} 
                      onChange={handleChange} 
                      className={`block w-full pl-11 pr-4 py-3.5 rounded-2xl bg-slate-50 dark:bg-slate-800 border ${errors.phone ? 'border-red-400 ring-2 ring-red-500/10' : 'border-slate-200 dark:border-slate-700 focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10'} text-slate-900 dark:text-white placeholder-slate-400 transition-all font-medium`} 
                      placeholder="Contoh: 081234567890" 
                    />
                  </div>
                  {errors.phone && <p className="mt-2 text-xs text-red-500 flex items-center font-bold uppercase tracking-tight"><AlertCircle size={12} className="mr-1" />{errors.phone}</p>}
                </div>
              </div>
            </section>

            <hr className="border-slate-100 dark:border-slate-800" />

            <section>
              <h3 className="text-lg font-black text-slate-800 dark:text-white flex items-center mb-6 uppercase tracking-tight">
