               <dd className="mt-2 text-2xl font-bold text-slate-900 dark:text-white">{formatRupiah(sisaTotal)}</dd>
               <div className="mt-2 text-xs text-slate-500">Tersedia untuk paket baru</div>
            </div>
            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700">
               <dt className="text-sm font-medium text-slate-500 dark:text-slate-400">Efisiensi</dt>
               <dd className="mt-2 text-2xl font-bold text-green-600 dark:text-green-400">98.2%</dd>
               <div className="mt-2 text-xs text-slate-500">Penyerapan optimal</div>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white dark:bg-slate-800 shadow-sm rounded-2xl border border-slate-100 dark:border-slate-700 p-6">
              <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-6">Realisasi vs Perencanaan Bulanan</h3>
              <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={MOCK_COST_REPORTS}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#94a3b8" opacity={0.1} />
                    <XAxis dataKey="month" tick={{fill: '#94a3b8'}} axisLine={false} />
                    <YAxis hide />
                    <Tooltip 
                      formatter={(value: any) => formatRupiah(Number(value))}
                      contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff'}}
                    />
                    <Bar dataKey="estimasi" name="Rencana" fill="#e2e8f0" radius={[4, 4, 0, 0]} />
                    <Bar dataKey="realisasi" name="Realisasi" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="bg-white dark:bg-slate-800 shadow-sm rounded-2xl border border-slate-100 dark:border-slate-700 p-6">
              <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-6">Proporsi Belanja</h3>
              <div className="h-72 flex items-center justify-center">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={COST_BY_CATEGORY}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={90}
                      paddingAngle={5}
                      dataKey="value"
                      stroke="none"
                    >
                      {COST_BY_CATEGORY.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip formatter={(value: any) => formatRupiah(Number(value))} />
                    <Legend />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ================= TAB 2: BUKU KOMITMEN ================= */}
      {activeTab === 'komitmen' && (
        <div className="space-y-6 animate-in fade-in duration-300">

          {/* Header Actions */}
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-blue-600 dark:bg-blue-900 p-6 rounded-2xl shadow-lg text-white">
             <div>
                <h2 className="text-xl font-bold">Buku Kontrol Anggaran</h2>
                <p className="text-blue-100 text-sm mt-1">Pantau Pagu vs Komitmen agar tidak Overbudget.</p>
             </div>
             <div className="flex gap-3">
                <button 
                  onClick={handleExportExcel}
                  className="flex items-center px-4 py-2 bg-white/10 hover:bg-white/20 backdrop-blur-sm rounded-lg font-semibold transition-colors border border-white/20"
                >
                   <FileSpreadsheet className="w-4 h-4 mr-2" /> Export Excel
                </button>
             </div>
          </div>

          {/* Summary Stats */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
             <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm">
                <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">Total Pagu Kegiatan</p>
                <p className="text-xl font-bold text-slate-900 dark:text-white mt-1">{formatRupiah(totalPagu)}</p>
             </div>
             <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm">
                <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">Total Terkontrak</p>
                <p className="text-xl font-bold text-blue-600 dark:text-blue-400 mt-1">{formatRupiah(totalKomitmen)}</p>
             </div>
             <div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 shadow-sm">
                <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">Sisa Anggaran</p>
                <p className={`text-xl font-bold mt-1 ${sisaTotal < 0 ? 'text-red-600' : 'text-green-600'}`}>{formatRupiah(sisaTotal)}</p>
             </div>
          </div>

          {/* Table */}
          <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
            <div className="p-4 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 flex justify-between items-center">
               <h3 className="font-bold text-slate-900 dark:text-white">Rincian Paket Pekerjaan</h3>
               <div className="relative w-64">
                  <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Cari paket..." 
                    className="w-full pl-9 pr-4 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  />
               </div>
            </div>
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                <thead className="bg-slate-50 dark:bg-slate-900">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Paket / ID</th>
                    <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Penyedia</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Pagu Anggaran</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Nilai Kontrak</th>
                    <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Sisa</th>
                    <th className="px-6 py-3 text-center text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-200 dark:divide-slate-700 bg-white dark:bg-slate-800">
                  {COMMITMENT_DATA.map((item) => {
                    const sisa = item.pagu - item.commitment;
                    const percentage = (item.commitment / item.pagu) * 100;
                    let statusColor = 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400';
                    let statusText = 'Aman';

                    if (percentage > 100) {
                      statusColor = 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400';
                      statusText = 'Overbudget';
                    } else if (percentage > 90) {
                      statusColor = 'bg-orange-100 text-orange-800 dark:bg-orange-900/30 dark:text-orange-400';
                      statusText = 'Warning';
                    }

                    return (
                      <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="font-bold text-slate-900 dark:text-white text-sm">{item.name}</div>
                          <div className="text-xs text-slate-500 font-mono mt-0.5">{item.id}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-slate-300">
                          {item.vendor}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium text-slate-900 dark:text-white">
                          {formatRupiah(item.pagu)}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-bold text-blue-600 dark:text-blue-400">
                          {formatRupiah(item.commitment)}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                          <span className={sisa < 0 ? 'text-red-600' : 'text-slate-900 dark:text-white'}>
                             {formatRupiah(sisa)}
                          </span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-center">
                           <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${statusColor}`}>
                             {percentage > 90 && <AlertTriangle className="w-3 h-3 mr-1" />}
                             {statusText}
                           </span>
                           <div className="mt-1 w-full bg-slate-100 dark:bg-slate-700 rounded-full h-1">
                              <div 
                                className={`h-1 rounded-full ${percentage > 100 ? 'bg-red-500' : percentage > 90 ? 'bg-orange-500' : 'bg-green-500'}`} 
                                style={{ width: `${Math.min(percentage, 100)}%` }}
                              ></div>
                           </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* ================= TAB 3: E-PURCHASING ================= */}
      {activeTab === 'epurchasing' && (
         <div className="space-y-6 animate-in fade-in duration-300">

            {/* Tools & Links */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="bg-gradient-to-br from-slate-900 to-slate-800 text-white rounded-2xl p-6 shadow-lg relative overflow-hidden group">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-10 -mt-10 blur-2xl group-hover:bg-white/10 transition-all"></div>
                  <div className="relative z-10">
                     <h3 className="text-xl font-bold flex items-center gap-2">
                        <ShoppingCart className="w-6 h-6 text-blue-400" /> E-Katalog LKPP
                     </h3>
                     <p className="text-slate-300 text-sm mt-2 mb-6">Akses cepat ke portal katalog nasional untuk pengadaan material dan alat.</p>
                     <a 
                        href="https://katalog.inaproc.id/" 
                        target="_blank" 
                        rel="noreferrer"
                        className="inline-flex items-center px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold transition-colors shadow-lg shadow-blue-600/30"
                     >
                        Buka Katalog Nasional <ExternalLink className="w-4 h-4 ml-2" />
                     </a>
                  </div>
               </div>

               <div className="bg-white dark:bg-slate-800 rounded-2xl p-6 shadow-sm border border-slate-100 dark:border-slate-700">
                  <h3 className="font-bold text-slate-900 dark:text-white mb-4 flex items-center gap-2">
                     <Copy className="w-5 h-5 text-slate-500" /> Template Paket Pekerjaan
                  </h3>
                  <div className="space-y-3">
                     <div className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700">
                        <div className="text-sm font-medium text-slate-700 dark:text-slate-300">Spek Teknis Aspal Cold Mix</div>
                        <button onClick={() => handleCopy("Spesifikasi Teknis: Aspal Cold Mix Kemasan 25kg, Grade A, SNI...")} className="text-blue-600 hover:text-blue-800 text-xs font-bold flex items-center">
                           Salin <Copy className="w-3 h-3 ml-1" />
                        </button>
                     </div>
                     <div className="flex items-center justify-between p-3 bg-slate-50 dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-700">
                        <div className="text-sm font-medium text-slate-700 dark:text-slate-300">Syarat Kualifikasi Penyedia</div>
                        <button onClick={() => handleCopy("Syarat Kualifikasi: Memiliki SIUJK, NIB, dan Pengalaman sejenis...")} className="text-blue-600 hover:text-blue-800 text-xs font-bold flex items-center">
                           Salin <Copy className="w-3 h-3 ml-1" />
                        </button>
                     </div>
                  </div>
               </div>
            </div>

            {/* Transaction List */}
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700">
               <div className="p-6 border-b border-slate-100 dark:border-slate-700 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
                  <h3 className="font-bold text-slate-900 dark:text-white text-lg">Riwayat Transaksi E-Purchasing</h3>
                  <button className="flex items-center px-4 py-2 bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-300 rounded-lg text-sm font-bold hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors">
                     <UploadCloud className="w-4 h-4 mr-2" /> Upload Bukti Transaksi
                  </button>
               </div>
               <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                     <thead className="bg-slate-50 dark:bg-slate-900/50">
                        <tr>
                           <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Tgl / ID</th>
                           <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Item Pengadaan</th>
                           <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">No. SPK / PO</th>
                           <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Status</th>
                           <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">Aksi</th>
                        </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                        {EPURCHASING_DATA.map((item) => (
                           <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30">
                              <td className="px-6 py-4 whitespace-nowrap">
                                 <div className="text-sm font-bold text-slate-900 dark:text-white">{item.date}</div>
                                 <div className="text-xs text-slate-500">{item.id}</div>
                              </td>
                              <td className="px-6 py-4">
                                 <div className="text-sm text-slate-900 dark:text-white font-medium">{item.item}</div>
                                 <div className="text-xs text-slate-500">Qty: {item.qty}</div>
                              </td>
                              <td className="px-6 py-4 whitespace-nowrap">
                                 <span className="px-2 py-1 bg-slate-100 dark:bg-slate-700 rounded font-mono text-xs text-slate-700 dark:text-slate-300 select-all">
                                    {item.spk}
                                 </span>
                              </td>
                              <td className="px-6 py-4 whitespace-nowrap">
                                 <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                                    item.status === 'Selesai' ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400' : 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400'
                                 }`}>
                                    {item.status === 'Selesai' && <CheckCircle2 className="w-3 h-3 mr-1" />}
                                    {item.status}
                                 </span>
                              </td>
                              <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                 <button className="text-blue-600 hover:text-blue-900 dark:text-blue-400 dark:hover:text-blue-300 text-xs font-bold border border-blue-200 dark:border-blue-800 px-3 py-1.5 rounded-lg hover:bg-blue-50 dark:hover:bg-blue-900/30 transition-colors">
                                    Detail
                                 </button>
                              </td>
                           </tr>
                        ))}
                     </tbody>
                  </table>
               </div>
            </div>
         </div>
      )}

    </AdminLayout>
  );
};

export default Reports;
